// MODULE: Memory Index Discovery Helpers
// в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/* ------- 1. DEPENDENCIES ------- */

import fs from 'fs';
import path from 'path';

import { toErrorMessage } from '../utils/index.js';
import {
  extractSpecFolderFromGraphMetadataPath,
  GRAPH_METADATA_FILENAME,
  isGraphMetadataPath,
  matchesSpecDocumentPath,
  SPEC_DOCUMENT_FILENAMES,
  shouldDescendSpecDiscoveryDirectory,
} from '../lib/config/spec-doc-paths.js';
import { getCanonicalPathKey } from '../lib/utils/canonical-path.js';
import { isIndexableConstitutionalMemoryPath, shouldIndexForMemory } from '../lib/utils/index-scope.js';

// Feature catalog: Workspace scanning and indexing (memory_index_scan)
// Feature catalog: Spec folder description discovery


/* ------- 2. CONSTANTS ------- */

const SPEC_DISCOVERY_MAX_DEPTH = 20;
const SPEC_DISCOVERY_MAX_NODES = 50_000;

interface DiscoveryWalkState {
  visitedNodes: number;
  maxNodesExceeded: boolean;
  depthExceeded: boolean;
  warnings: string[];
}

function shouldAbortDiscoveryWalk(state: DiscoveryWalkState, label: string): boolean {
  if (state.maxNodesExceeded) {
    return true;
  }

  state.visitedNodes += 1;
  if (state.visitedNodes > SPEC_DISCOVERY_MAX_NODES) {
    const warning = `[memory-index-discovery] ${label} aborted after ${SPEC_DISCOVERY_MAX_NODES} filesystem nodes`;
    console.warn(warning);
    state.warnings.push(warning);
    state.maxNodesExceeded = true;
    return true;
  }

  return false;
}

/* ------- 3. DISCOVERY FUNCTIONS ------- */

export interface SpecDiscoveryOptions {
  specFolder?: string | null;
}

export interface DiscoveryCapExceeded {
  maxNodes: boolean;
  depth: boolean;
  gitignoreSize: boolean;
}

export type DiscoveryFileList = string[] & {
  warnings: string[];
  capExceeded: DiscoveryCapExceeded;
};

function createDiscoveryState(): DiscoveryWalkState {
  return {
    visitedNodes: 0,
    maxNodesExceeded: false,
    depthExceeded: false,
    warnings: [],
  };
}

function attachDiscoveryMetadata(results: string[], state: DiscoveryWalkState): DiscoveryFileList {
  return Object.assign(results, {
    warnings: [...state.warnings],
    capExceeded: {
      maxNodes: state.maxNodesExceeded,
      depth: state.depthExceeded,
      gitignoreSize: false,
    },
  });
}

// Callers pass the scope in several natural shapes: the specs-root-relative
// form, the workspace path that still carries the `.opencode/specs/` segment,
// an absolute filesystem path, or a bare leaf folder name. Reduce all of them
// to the specs-root-relative form so the comparison against relativePath is
// stable regardless of which shape the caller used.
function normalizeSpecFolderScope(specFolder: string, specsRoot: string): string {
  let scope = specFolder.replace(/\\/g, '/').replace(/\/+$/, '').replace(/^\.\//, '');
  if (path.isAbsolute(scope)) {
    const rel = path.relative(specsRoot, scope).replace(/\\/g, '/');
    return rel && !rel.startsWith('..') ? rel : scope;
  }
  const marker = '.opencode/specs/';
  const markerIdx = scope.indexOf(marker);
  if (markerIdx !== -1) {
    scope = scope.slice(markerIdx + marker.length);
  }
  return scope;
}

function matchesScopedSpecFolder(candidatePath: string, specsRoot: string, specFolder?: string | null): boolean {
  if (!specFolder) {
    return true;
  }

  const scope = normalizeSpecFolderScope(specFolder, specsRoot);
  const relativePath = path.relative(specsRoot, candidatePath).replace(/\\/g, '/');
  if (relativePath === scope || relativePath.startsWith(`${scope}/`)) {
    return true;
  }
  // A single-segment scope (a bare folder name) matches any file nested under a
  // directory of that name, preserving the documented leaf-name scoping form.
  if (scope.length > 0 && !scope.includes('/')) {
    const parentSegments = relativePath.split('/').slice(0, -1);
    return parentSegments.includes(scope);
  }
  return false;
}

/**
 * Discover spec folder documents (.opencode/specs/ directory tree).
 * Gated by SPEC_DOCUMENT_FILENAMES (see lib/config/spec-doc-paths.ts) вЂ”
 * currently: spec.md, plan.md, tasks.md, checklist.md, decision-record.md,
 * implementation-summary.md, research.md (incl. research/research.md),
 * handover.md, resource-map.md, review-report.md (review/), description.json
 * (incl. iteration packs' backfilled metadata under <pack>/iterations/).
 *
 * Excludes scratch/, memory/, and hidden directories; iteration dirs are
 * descended but only allowlisted filenames are collected.
 */

